Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word:

```cpp
#include <iostream>
#include <fstream>
#include <sstream>
#include <string>
#include <map>
using namespace std;

int countWordOccurrences(string fileName, string targetWord) {
    int count = 0;
    ifstream file(fileName);
    string line, word;

    if (file.is_open()) {
        while (getline(file, line)) {
            stringstream lineStream(line);
            while (getline(lineStream, word, ' ')) {
                if (word == targetWord) {
                    count++;
                }
            }
        }
        file.close();
    } else {
        cout << "Unable to open file";
        return -1; // return error code
    }

    return count;
}

int main() {
    string fileName, targetWord;
    cout << "Enter the file name: ";
    cin >> fileName;
    cout << "Enter the target word: ";
    cin >> targetWord;

    int count = countWordOccurrences(fileName, targetWord);
    if (count != -1) {
        cout << "The word '" << targetWord << "' occurs " << count << " times in the file." << endl;
    }

    return 0;
}
```

